return {
  ["interview3.a1.text0"] = "First things first: leading this investigation must have put great pressure on you. How have you been handling it?",
  ["interview3.a1.answer1.text"] = "I'm a professional. Part of my job is handling the pressure of leadership.",
  ["interview3.a1.answer2.text"] = "No one can be ready for something like this, so I'm adjusting and learning as we go.",
  ["interview3.a1.answer3.text"] = "It's been hard, of course, but I have a great team backing me up.",
  ["interview3.a2.text0"] = "You've been the face of this operation, but there's a whole team behind you. Let's talk about them for a bit...",
  ["interview3.a2.answer1.text"] = "Of course.",
  ["interview3.a2.answer2.text"] = "If we have to.",
  ["interview3.a2.answer2.reply0"] = "We totally have to.",
  ["interview3.a2.answer3.text"] = "Mhm.",
  ["interview3.a3.text0"] = "Jennifer Reyes, expert psychologist and criminal profiler. What does she bring to the table?",
  ["interview3.a3.answer1.text"] = "Jennifer's insight into the criminal mind allows us to predict their movements and to better understand their objectives.",
  ["interview3.a3.answer2.text"] = "When you're dealing with the people we are, it takes a specialist to comprehend the distorted way their mind works.",
  ["interview3.a3.answer3.text"] = "Jennifer focuses her efforts on building a rapport with the people we investigate. Without empathy, there can be no dialogue.",
  ["interview3.a3.answer3.reply0"] = "Sounds cool.",
  ["interview3.a4.text0"] = "Mordecai Ficher, an officer with a long history of fighting organized crime. What's he about?",
  ["interview3.a4.answer1.text"] = "He's our boots-on-the-ground man, an excellent detective and a better tracker than a bloodhound.",
  ["interview3.a4.answer1.reply0"] = "Like in the movies. Cool.",
  ["interview3.a4.answer2.text"] = "Mordecai has experience with underground criminal organizations and is crucial in follow up on leads and getting results.",
  ["interview3.a4.answer3.text"] = "Mordecai knows what the weak spots in a criminal organization are. And he knows best how to use them to our advantage.",
  ["interview3.a5.text0"] = "Tab Thompson, analyst and technical expert. How are their skills valuable?",
  ["interview3.a5.answer1.text"] = "Tab's insight allows us to make connections we would have never seen.",
  ["interview3.a5.answer2.text"] = "Tab's analytical skills are very important when combing through databases and files, making sure we don't miss anything.",
  ["interview3.a5.answer3.text"] = "Tab's procedural knowledge enables us to use all legal tools at our disposal, hitting the Front with everything we've got, without wasting time muddled in bureaucracy.",
  ["interview3.a5.answer3.reply0"] = "Bureaucracy can be a pain in the ass... yup.",
  ["interview3.a6.text0"] = "Recently, Joseph Ward has joined your team. What can this old dog teach you?",
  ["interview3.a6.answer1.text"] = "History repeats itself, and Joseph has been through a similar situation once already. He's the one we turn to when we're stuck.",
  ["interview3.a6.answer1.reply0"] = "Lucky.",
  ["interview3.a6.answer2.text"] = "Joseph's experience is invaluable when tough decisions need to be made.",
  ["interview3.a6.answer3.text"] = "Joseph is not a dog. He is a very competent police officer. As good as any of us.",
  ["interview3.a6.answer3.reply0"] = "I... uh. I'll put down that he's great.",
  ["interview3.a7.text0"] = "What sort of work dynamic do you have? Everyone getting along?",
  ["interview3.a7.answer1.text"] = "We've had our disagreements, of course, but that is just reflective of everyone's commitment and involvement.",
  ["interview3.a7.answer2.text"] = "We're a team, and we have a job to do. We're not here to make friends; we're here to keep people safe.",
  ["interview3.a7.answer3.text"] = "After what we've been through together, I must say, we're very close. We trust and respect each other.",
  ["interview3.a7.answer3.reply0"] = "Aww. Neat.",
  ["interview3.a8.text0"] = "You've had to work fast, jumping from crisis to crisis. What's your secret?",
  ["interview3.a8.answer1.text"] = "I don't let myself get bogged down in red tape. The stakes are too high for that.",
  ["interview3.a8.answer2.text"] = "I make sure we're always well prepared. We only have one shot at this, no do-overs.",
  ["interview3.a8.answer3.text"] = "I've learned to trust my instincts and never to hesitate when I have to act.",
  ["interview3.a9.text0"] = "When you know lives are on the line, what keeps you focused, sane?",
  ["interview3.a9.answer1.text"] = "I take it one day at a time. Solve what I have in front of me first.",
  ["interview3.a9.answer1.reply0"] = "Good, good.",
  ["interview3.a9.answer2.text"] = "The knowledge that I've done my best.",
  ["interview3.a9.answer3.text"] = "I try not to think about it too much. That sort of stress ruins you.",
  ["interview3.a10.text0"] = "What is your approach when talking to Front members?",
  ["interview3.a10.answer1.text"] = "I try to understand where they are coming from and to show them their mistakes.",
  ["interview3.a10.answer2.text"] = "If their survival instinct kicks in, they become cooperative very fast. Fear is our most effective tool.",
  ["interview3.a10.answer2.reply0"] = "Sounds, uh... harsh.",
  ["interview3.a10.answer3.text"] = "With diligent questioning, they quickly start contradicting themselves. That is when I catch them.",
  ["interview3.a11.text0"] = "Have you ever found yourself agreeing with something a Front member said?",
  ["interview3.a11.answer1.text"] = "Absolutely not. Let's not forget what these people are.",
  ["interview3.a11.answer1.reply0"] = "Hmh...",
  ["interview3.a11.answer2.text"] = "Of course. They are guilty for their actions, not for their ideas.",
  ["interview3.a11.answer3.text"] = "Sometimes, yes. It's part of my job to use the most persuasive approach.",
  ["interview3.a12.text0"] = "Many of those you've put behind bars had regular lives before. Do you ever think about that?",
  ["interview3.a12.answer1.text"] = "No. I think about their crimes and those they've hurt.",
  ["interview3.a12.answer2.text"] = "Yes, and it shows how insidious the Front's propaganda can be.",
  ["interview3.a12.answer3.text"] = "Yes, of course. These people are everywhere: our neighbors, our family, our friends. It worries me.",
  ["interview3.a13.text0"] = "Last question. Do you feel proud of what you've accomplished so far?",
  ["interview3.a13.answer1.text"] = "Yes, we've done good work here.",
  ["interview3.a13.answer1.reply0"] = "Okay! Well, that's it. Thanks for all of this, then!",
  ["interview3.a13.answer2.text"] = "Pride has nothing to do with it.",
  ["interview3.a13.answer2.reply0"] = "I see. Okay. Well, that's it. Thanks!",
  ["interview3.a13.answer3.text"] = "I've had to do things I'm not proud of. But they were necessary.",
  ["interview3.a13.answer3.reply0"] = "Hard stuff. That's all. Thanks.",
}

